import fs from"fs-extra";import path from"node:path";import{buildPPIconsManifest}from"./ppicons-manifest.js";const START_MARKER="\x3c!-- ppicons:start --\x3e",END_MARKER="\x3c!-- ppicons:end --\x3e";function getInstructionFrontmatter(e){return["---",'description: "Use when working with ppicons, PPIcons icon components, Prisma PHP/PHPX icons, Caspian icons, icon installation, icon updates, or icon imports."','name: "PPIcons AI Context"',`applyTo: "${[e.project.manifestFile,`${e.project.componentsDirectory}/**`].join(", ")}"`,"---",""].join("\n")}function escapeRegExp(e){return e.replace(/[.*+?^${}()|[\]\\]/g,"\\$&")}function hasFrontmatter(e){return e.replace(/^\uFEFF/,"").startsWith("---\n")}function getPhpUsageExample(e){return["```php","<?php","",`use ${e}\\Search;`,"","?>","","<Search />",'<Search class="size-4" />',"```"].join("\n")}function getCaspianUsageExample(){return["```html","\x3c!-- @import { Search } from ../../lib/ppicons --\x3e","","<Search />",'<Search class="size-4" />',"```"].join("\n")}function getCatalogResponseExample(){return["```json","{",'  "id": 166531,','  "name": "search",','  "componentName": "Search",','  "svg": "<svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" class=\\"lucide lucide-search\\"><circle cx=\\"11\\" cy=\\"11\\" r=\\"8\\"/><path d=\\"m21 21-4.3-4.3\\"/></svg>",','  "createdAt": 1774923647142,','  "updatedAt": 1774923647142',"}","```"].join("\n")}function buildManagedBlockContent(e){const n=["# PPIcons AI Context","","This project uses `ppicons` to generate reusable icon components.","",`- Project type: ${e.project.type}`,`- Framework: ${e.project.framework}`,`- Language mode: ${e.project.language}`,`- Framework config file: ${e.project.configFile}`,`- Manifest file: ${e.project.manifestFile}`,`- Components directory: ${e.project.componentsDirectory}`,`- Icons directory: ${e.project.iconsDirectory}`,`- Installed icon count: ${e.icons.length}`,"- Full installed icon inventory: `ppicons.json`","","## Installing Icons","","When a requested icon does not exist yet, install it with `ppicons` instead of hand-writing a component.","",`- Add one icon: \`${e.commands.addOne}\``,`- Add multiple icons: \`${e.commands.addMany}\``,`- Add the full set: \`${e.commands.addAll}\``,`- Refresh installed icons: \`${e.commands.updateInstalled}\``,"","## Discovering Available Icons","","Use the catalog API to find icon names before installing them.","",`- Fetch all available icons: \`${e.catalogApi.listAll.method} ${e.catalogApi.listAll.url}\``,`- Fetch one icon by name: \`${e.catalogApi.getOne.method} ${e.catalogApi.getOne.exampleUrl}\``,"- The single-icon endpoint returns one JSON object.","- The `icon=all` endpoint returns a JSON array of objects with the same shape.","","Single icon response example:","",getCatalogResponseExample(),"","## Using Installed Icons","",`Use ${e.usage.syntax}.`,""];return"prisma-php"===e.project.type?n.push("For Prisma PHP or PHPX templates:","",getPhpUsageExample(e.usage.entry),""):n.push("For Caspian templates:","",getCaspianUsageExample(),"","Adjust the relative import path so it points to the icons directory from the current template file.",""),n.push("## Notes","","- Reuse installed icons from `ppicons.json` before adding new ones.",`- Generated icon files follow this pattern: \`${e.usage.filePattern}\``,`- The import entry for this project is \`${e.usage.entry}\``),n.join("\n")}function mergeManagedBlock(e,n){const t=e.replace(/\r\n/g,"\n"),o=new RegExp(`${escapeRegExp(START_MARKER)}[\\s\\S]*?${escapeRegExp(END_MARKER)}`);return o.test(t)?t.replace(o,n).trimEnd()+"\n":0===t.trim().length?`${n}\n`:`${t.trimEnd()}\n\n${n}\n`}async function writePPIconsInstructionFile(e,n){const t=await buildPPIconsManifest(e),o=getInstructionFrontmatter(t),i=[START_MARKER,buildManagedBlockContent(t),END_MARKER].join("\n");await fs.ensureDir(path.dirname(n));const s=await fs.pathExists(n)?(()=>{const e=fs.readFileSync(n,"utf8"),t=mergeManagedBlock(e,i);return hasFrontmatter(e)?t:`${o}${t}`})():`${o}${i}\n`;return await fs.writeFile(n,s,"utf8"),n}export async function writePPIconsCopilotInstructions(e){return writePPIconsInstructionFile(e,path.join(e.projectRoot,".github","instructions","ppicons.instructions.md"))}